import { useState, useEffect } from 'react';

interface UserProfile {
  id: number;
  username: string;
  displayName: string;
  avatarUrl: string | null;
  bio: string | null;
  location: string | null;
  website: string | null;
  karma: number;
  isVerified: boolean;
  createdAt: string;
}

interface ProfileStats {
  posts: number;
  comments: number;
  followers: number;
  following: number;
