            {profile.website && (
              <a href={profile.website} target="_blank" rel="noopener noreferrer"
                 className="text-blue-600 hover:underline">{profile.website}</a>
            )}
          </div>
          <p className="text-sm text-gray-400 mt-1">
            Joined {new Date(profile.createdAt).toLocaleDateString()}
          </p>
        </div>
      </div>

      {stats && (
        <div className="flex justify-around border-y py-3 text-center">
          <div><strong>{stats.posts}</strong><br /><span className="text-sm text-gray-500">Posts</span></div>
          <div><strong>{stats.comments}</strong><br /><span className="text-sm text-gray-500">Comments</span></div>
          <div><strong>{stats.followers}</strong><br /><span className="text-sm text-gray-500">Followers</span></div>
          <div><strong>{stats.following}</strong><br /><span className="text-sm text-gray-500">Following</span></div>
          <div><strong>{profile.karma}</strong><br /><span className="text-sm text-gray-500">Karma</span></div>
        </div>
