            className={`flex-1 py-3 text-center capitalize ${
              activeTab === tab ? 'border-b-2 border-blue-600 font-semibold' : 'text-gray-500'
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      <div className="p-4">
        {activeTab === 'posts' && <p>User posts will render here.</p>}
        {activeTab === 'comments' && <p>User comments will render here.</p>}
        {activeTab === 'likes' && <p>Liked content will render here.</p>}
      </div>
    </div>
  );
}

import { useState, useRef, FormEvent } from 'react';

interface ProfileForm {
  displayName: string;
  bio: string;
  location: string;
  website: string;
}

export default function ProfileSettings({ initial }: { initial: ProfileForm & { avatarUrl: string | null } }) {
  const [form, setForm] = useState<ProfileForm>({
    displayName: initial.displayName,
    bio: initial.bio,
    location: initial.location,
    website: initial.website,
  });
  const [avatarPreview, setAvatarPreview] = useState(initial.avatarUrl);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState('');
  const fileRef = useRef<HTMLInputElement>(null);

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setAvatarPreview(URL.createObjectURL(file));
    const formData = new FormData();
    formData.append('avatar', file);
    const res = await fetch('/api/users/me/avatar', { method: 'POST', body: formData });
    const data = await res.json();
    if (res.ok) setAvatarPreview(data.avatarUrl);
  };

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setSaving(true);
    const res = await fetch('/api/users/me', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        display_name: form.displayName,
        bio: form.bio,
        location: form.location,
        website: form.website,
      }),
    });
    setSaving(false);
    setMessage(res.ok ? 'Profile updated!' : 'Failed to save.');
    setTimeout(() => setMessage(''), 3000);
  };

  const updateField = (field: keyof ProfileForm, value: string) =>
    setForm(prev => ({ ...prev, [field]: value }));

  return (
    <form onSubmit={handleSubmit} className="max-w-lg mx-auto p-6 space-y-6">
      <h2 className="text-xl font-bold">Edit Profile</h2>

      <div className="flex items-center gap-4">
        <img
          src={avatarPreview || '/default-avatar.png'}
          alt="Avatar"
          className="w-20 h-20 rounded-full object-cover cursor-pointer"
          onClick={() => fileRef.current?.click()}
        />
        <input ref={fileRef} type="file" accept="image/*" className="hidden"
               onChange={handleAvatarChange} />
        <button type="button" onClick={() => fileRef.current?.click()}
                className="text-blue-600 text-sm">Change avatar</button>
      </div>

      <label className="block">
        <span className="text-sm font-medium">Display Name</span>
        <input type="text" value={form.displayName} maxLength={100}
               onChange={e => updateField('displayName', e.target.value)}
               className="mt-1 block w-full border rounded px-3 py-2" />
      </label>

      <label className="block">
        <span className="text-sm font-medium">Bio</span>
        <textarea value={form.bio} maxLength={500} rows={3}
                  onChange={e => updateField('bio', e.target.value)}
                  className="mt-1 block w-full border rounded px-3 py-2" />
      </label>

      <label className="block">
        <span className="text-sm font-medium">Location</span>
        <input type="text" value={form.location} maxLength={100}
               onChange={e => updateField('location', e.target.value)}
               className="mt-1 block w-full border rounded px-3 py-2" />
      </label>

      <label className="block">
        <span className="text-sm font-medium">Website</span>
        <input type="url" value={form.website} maxLength={255}
               onChange={e => updateField('website', e.target.value)}
               className="mt-1 block w-full border rounded px-3 py-2" />
      </label>

      {message && <p className="text-green-600 text-sm">{message}</p>}
      <button type="submit" disabled={saving}
              className="bg-blue-600 text-white px-6 py-2 rounded hover:bg-blue-700 disabled:opacity-50">
        {saving ? 'Saving...' : 'Save Changes'}
      </button>
    </form>
  );
}

